const chain = msg.proxlab || {};
const steps = chain.steps || [];

let report = '=== System Diagnosis Report ===\n\n';
steps.forEach((step, i) => {
    report += `--- Step ${i + 1}: ${step.agent_name || step.agent_id} ---\n`;
    report += `Model: ${step.model || 'N/A'} | Tokens: ${step.tokens || 0} | Time: ${step.duration_ms || 0}ms\n`;
    report += `${step.response_text || '(no response)'}\n\n`;
});

report += `Total steps: ${steps.length}`;
msg.payload = report;
return msg;

const chainId = msg.payload.chain_id || msg.payload.id;
flow.set('diagnosis_chain_id', chainId);
msg.payload = `Chain created with ID: ${chainId}. Copy this ID into the 'Run Diagnosis Chain' node config.`;
return msg;
